data "aws_iam_policy_document" "assume" {
  statement {
    actions = ["sts:AssumeRole"]
    principals { type = "Service" identifiers = ["ecs-tasks.amazonaws.com"] }
  }
}

resource "aws_iam_role" "execution" {
  name               = "checkout-execution"
  assume_role_policy = data.aws_iam_policy_document.assume.json
}
resource "aws_iam_role_policy_attachment" "exec_managed" {
  role       = aws_iam_role.execution.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}
resource "aws_iam_role_policy" "exec_secrets" {
  role   = aws_iam_role.execution.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [{ Effect = "Allow", Action = "secretsmanager:GetSecretValue", Resource = var.db_secret_arn }]
  })
}

resource "aws_iam_role" "task" {
  name               = "checkout-task"
  assume_role_policy = data.aws_iam_policy_document.assume.json
}

resource "aws_security_group" "alb" {
  name = "checkout-alb" vpc_id = var.vpc_id
  ingress { from_port = 443 to_port = 443 protocol = "tcp" cidr_blocks = ["0.0.0.0/0"] }
  egress  { from_port = 0 to_port = 0 protocol = "-1" cidr_blocks = ["0.0.0.0/0"] }
}
resource "aws_security_group" "task" {
  name = "checkout-task" vpc_id = var.vpc_id
  ingress { from_port = 8080 to_port = 8080 protocol = "tcp" security_groups = [aws_security_group.alb.id] }
  egress  { from_port = 0 to_port = 0 protocol = "-1" cidr_blocks = ["0.0.0.0/0"] }
}

resource "aws_lb" "this" {
  name = "checkout-alb" load_balancer_type = "application"
  subnets = var.public_subnet_ids security_groups = [aws_security_group.alb.id]
}
resource "aws_lb_target_group" "this" {
  name = "checkout-tg" port = 8080 protocol = "HTTP" vpc_id = var.vpc_id
  target_type = "ip"
  health_check { path = "/healthz" matcher = "200" interval = 15 healthy_threshold = 2 unhealthy_threshold = 3 }
}
resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.this.arn port = 443 protocol = "HTTPS"
  certificate_arn = var.cert_arn
  default_action { type = "forward" target_group_arn = aws_lb_target_group.this.arn }
}

resource "aws_ecs_cluster" "this" { name = "prod" }

resource "aws_ecs_task_definition" "this" {
  family                   = "checkout-api"
  requires_compatibilities = ["FARGATE"]
  network_mode             = "awsvpc"
  cpu                      = "512"
  memory                   = "1024"
  execution_role_arn       = aws_iam_role.execution.arn
  task_role_arn            = aws_iam_role.task.arn
  container_definitions = jsonencode([{
    name      = "app"
    image     = var.image_uri
    essential = true
    portMappings = [{ containerPort = 8080, protocol = "tcp" }]
    secrets   = [{ name = "DB_PASSWORD", valueFrom = "${var.db_secret_arn}:password::" }]
    healthCheck = {
      command  = ["CMD-SHELL", "curl -f http://localhost:8080/healthz || exit 1"]
      interval = 15, timeout = 3, retries = 3, startPeriod = 30
    }
    logConfiguration = {
      logDriver = "awslogs"
      options = { "awslogs-group" = "/ecs/checkout-api", "awslogs-region" = var.region, "awslogs-stream-prefix" = "app" }
    }
  }])
}

resource "aws_ecs_service" "this" {
  name            = "checkout-api"
  cluster         = aws_ecs_cluster.this.id
  task_definition = aws_ecs_task_definition.this.arn
  desired_count   = 2
  launch_type     = "FARGATE"
  health_check_grace_period_seconds = 60
  network_configuration {
    subnets          = var.private_subnet_ids
    security_groups  = [aws_security_group.task.id]
    assign_public_ip = false
  }
  load_balancer {
    target_group_arn = aws_lb_target_group.this.arn
    container_name   = "app"
    container_port   = 8080
  }
  deployment_circuit_breaker { enable = true rollback = true }
  depends_on = [aws_lb_listener.https]
}
